'use client'
import {
  batch,
  cn,
  useControllableSignal,
  useSignal,
  useSignalEffect,
  useSignals,
} from '@cascivo/core'
import { builtin, currentLocale, t } from '@cascivo/i18n'
import { useRef } from 'react'
import { Calendar, type CalendarProps } from '../calendar/calendar'
import styles from './date-range-picker.module.css'

export interface DateRange {
  start: Date
  end: Date
}

export interface DateRangePreset {
  label: string
  range: DateRange
}

export interface DateRangePickerLabels {
  label?: string
  placeholder?: string
  start?: string
  end?: string
  apply?: string
  clear?: string
  previousMonth?: string
  nextMonth?: string
}

export interface DateRangePickerProps {
  value?: DateRange | null
  defaultValue?: DateRange
  onValueChange?: (range: DateRange) => void
  min?: Date
  max?: Date
  disabled?: (date: Date) => boolean
  presets?: DateRangePreset[]
  locale?: string
  placeholder?: string
  size?: 'sm' | 'md' | 'lg'
  labels?: DateRangePickerLabels
  className?: string
}

function dayMs(date: Date): number {
  return Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate())
}

function sameDay(a: Date | null | undefined, b: Date | null | undefined): boolean {
  if (!a || !b) return false
  return dayMs(a) === dayMs(b)
}

function addMonths(year: number, month: number, delta: number): { year: number; month: number } {
  const d = new Date(Date.UTC(year, month + delta, 1))
  return { year: d.getUTCFullYear(), month: d.getUTCMonth() }
}

export function DateRangePicker({
  value,
  defaultValue,
  onValueChange,
  min,
  max,
  disabled,
  presets,
  locale: localeProp,
  placeholder,
  size = 'md',
  labels,
  className,
}: DateRangePickerProps) {
  useSignals()
  const locale = localeProp ?? currentLocale()

  const resolvedPlaceholder = placeholder ?? t(builtin.dateRangePicker.placeholder)
  const resolvedApply = labels?.apply ?? t(builtin.dateRangePicker.apply)
  const resolvedClear = labels?.clear ?? t(builtin.dateRangePicker.clear)
  const resolvedPrev = labels?.previousMonth ?? t(builtin.calendar.previousMonth)
  const resolvedNext = labels?.nextMonth ?? t(builtin.calendar.nextMonth)

  const [range, setRange] = useControllableSignal<DateRange | null>({
    value: value === undefined ? undefined : value,
    defaultValue: defaultValue ?? null,
    onChange: (r) => {
      if (r) onValueChange?.(r)
    },
  })

  const open = useSignal(false)
  const pendingStart = useSignal<Date | null>(null)
  const hoverDate = useSignal<Date | null>(null)

  // Left calendar view; right is always +1 month.
  const seed = range.value?.start ?? defaultValue?.start ?? new Date()
  const viewYear = useSignal(seed.getUTCFullYear())
  const viewMonth = useSignal(seed.getUTCMonth())

  const rootRef = useRef<HTMLDivElement>(null)

  // Close on outside click.
  useSignalEffect(() => {
    if (!open.value) return
    const handler = (e: MouseEvent) => {
      if (rootRef.current && !rootRef.current.contains(e.target as Node)) open.value = false
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  })

  const openPanel = () => {
    open.value = true
  }
  const closePanel = () => {
    open.value = false
  }

  const advance = (delta: number) => {
    const next = addMonths(viewYear.value, viewMonth.value, delta)
    batch(() => {
      viewYear.value = next.year
      viewMonth.value = next.month
    })
  }

  const handleDayClick = (date: Date) => {
    const pending = pendingStart.value
    if (pending === null) {
      // First click: set pending start.
      pendingStart.value = date
      return
    }
    // Second click.
    if (sameDay(pending, date)) {
      // Same date twice → clear.
      batch(() => {
        pendingStart.value = null
        hoverDate.value = null
      })
      setRange(null)
      return
    }
    // Emit sorted range.
    const sorted =
      dayMs(pending) <= dayMs(date) ? { start: pending, end: date } : { start: date, end: pending }
    batch(() => {
      pendingStart.value = null
      hoverDate.value = null
    })
    setRange(sorted)
  }

  const applyPreset = (preset: DateRangePreset) => {
    batch(() => {
      pendingStart.value = null
      hoverDate.value = null
      viewYear.value = preset.range.start.getUTCFullYear()
      viewMonth.value = preset.range.start.getUTCMonth()
    })
    setRange(preset.range)
  }

  const clear = () => {
    batch(() => {
      pendingStart.value = null
      hoverDate.value = null
    })
    setRange(null)
  }

  // Range/preview boundaries — uses pending+hover while selecting, else the committed range.
  const activeStart = pendingStart.value ?? range.value?.start ?? null
  const activeEnd = pendingStart.value ? (hoverDate.value ?? null) : (range.value?.end ?? null)

  const lowKey = activeStart && activeEnd ? Math.min(dayMs(activeStart), dayMs(activeEnd)) : null
  const highKey = activeStart && activeEnd ? Math.max(dayMs(activeStart), dayMs(activeEnd)) : null

  const isInRange = (date: Date): boolean => {
    if (lowKey === null || highKey === null) return false
    const k = dayMs(date)
    return k > lowKey && k < highKey
  }
  const isRangeStart = (date: Date): boolean =>
    sameDay(date, activeStart) || (lowKey !== null && dayMs(date) === lowKey)
  const isRangeEnd = (date: Date): boolean =>
    sameDay(date, activeEnd) || (highKey !== null && dayMs(date) === highKey)

  const fmt = new Intl.DateTimeFormat(locale, { year: 'numeric', month: 'short', day: 'numeric' })
  const displayValue = range.value
    ? `${fmt.format(range.value.start)} → ${fmt.format(range.value.end)}`
    : ''

  const right = addMonths(viewYear.value, viewMonth.value, 1)

  const calendarProps: CalendarProps = {
    locale,
    size,
    ...(min !== undefined ? { min } : {}),
    ...(max !== undefined ? { max } : {}),
    ...(disabled !== undefined ? { disabled } : {}),
    hideNav: true,
    isInRange,
    isRangeStart,
    isRangeEnd,
    onValueChange: handleDayClick,
    onDayHover: (d: Date | null) => {
      hoverDate.value = d
    },
    labels: { previousMonth: resolvedPrev, nextMonth: resolvedNext },
  }

  return (
    <div
      ref={rootRef}
      className={cn(styles['wrapper'], className)}
      data-size={size}
      onKeyDown={(e) => {
        if (e.key === 'Escape' && open.value) {
          e.stopPropagation()
          closePanel()
        }
      }}
    >
      <button
        type="button"
        role="combobox"
        aria-expanded={open.value}
        aria-haspopup="dialog"
        aria-label={labels?.label ?? t(builtin.dateRangePicker.label)}
        className={styles['trigger']}
        onClick={open.value ? closePanel : openPanel}
      >
        <span className={cn(styles['value'], !displayValue ? styles['placeholder'] : undefined)}>
          {displayValue || resolvedPlaceholder}
        </span>
        <span className={styles['icon']} aria-hidden="true">
          📅
        </span>
      </button>
      <div role="dialog" className={styles['panel']} data-state={open.value ? 'open' : 'closed'}>
        {presets && presets.length > 0 && (
          <div className={styles['presets']}>
            {presets.map((preset) => (
              <button
                key={preset.label}
                type="button"
                className={styles['preset']}
                onClick={() => applyPreset(preset)}
              >
                {preset.label}
              </button>
            ))}
          </div>
        )}
        <div className={styles['calendars']}>
          <div className={styles['calNav']}>
            <button
              type="button"
              className={styles['navButton']}
              aria-label={resolvedPrev}
              onClick={() => advance(-1)}
            >
              ‹
            </button>
          </div>
          <Calendar month={viewMonth.value} year={viewYear.value} {...calendarProps} />
          <Calendar month={right.month} year={right.year} {...calendarProps} />
          <div className={styles['calNav']}>
            <button
              type="button"
              className={styles['navButton']}
              aria-label={resolvedNext}
              onClick={() => advance(1)}
            >
              ›
            </button>
          </div>
        </div>
        <div className={styles['footer']}>
          <button type="button" className={styles['clearBtn']} onClick={clear}>
            {resolvedClear}
          </button>
          <button type="button" className={styles['applyBtn']} onClick={closePanel}>
            {resolvedApply}
          </button>
        </div>
      </div>
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    position: relative;
    display: inline-flex;
    flex-direction: column;
    font-family: var(--cascivo-font-sans);

    &[data-size='sm'] {
      --_height: 2rem;
      --_font: var(--cascivo-text-sm);
      --_px: var(--cascivo-space-3);
    }
    &[data-size='md'] {
      --_height: 2.5rem;
      --_font: var(--cascivo-text-sm);
      --_px: var(--cascivo-space-4);
    }
    &[data-size='lg'] {
      --_height: 3rem;
      --_font: var(--cascivo-text-base);
      --_px: var(--cascivo-space-4);
    }
  }

  .trigger {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--cascivo-space-2);
    block-size: var(--_height, 2.5rem);
    min-inline-size: 18rem;
    padding-inline: var(--_px, var(--cascivo-space-4));
    font-family: var(--cascivo-font-sans);
    font-size: var(--_font, var(--cascivo-text-sm));
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    cursor: pointer;
    outline: none;
    text-align: start;
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      border-color: var(--cascivo-color-border-strong);
    }
    &:focus-visible {
      border-color: var(--cascivo-color-accent);
      box-shadow: 0 0 0 3px color-mix(in srgb, var(--cascivo-color-accent) 20%, transparent);
    }
  }

  .value {
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  .placeholder {
    color: var(--cascivo-color-text-subtle);
  }
  .icon {
    color: var(--cascivo-color-text-muted);
    font-style: normal;
  }

  .panel {
    position: absolute;
    inset-block-start: calc(100% + var(--cascivo-space-1));
    inset-inline-start: 0;
    z-index: var(--cascivo-z-dropdown);
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
    padding: var(--cascivo-space-3);
    background-color: var(--cascivo-color-surface-overlay);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    opacity: 0;
    visibility: hidden;
    translate: 0 -0.25rem;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter),
      visibility var(--cascivo-motion-enter);

    &[data-state='open'] {
      opacity: 1;
      visibility: visible;
      translate: 0 0;
    }

    @starting-style {
      &[data-state='open'] {
        opacity: 0;
        translate: 0 -0.25rem;
      }
    }
  }

  .calendars {
    display: flex;
    align-items: flex-start;
    gap: var(--cascivo-space-2);
  }

  .calNav {
    display: flex;
    align-items: center;
    padding-block-start: var(--cascivo-space-1);
  }

  .navButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 2rem;
    block-size: 2rem;
    background: none;
    border: 1px solid transparent;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    color: var(--cascivo-color-text-muted);
    font-size: var(--cascivo-text-base);
    outline: none;

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
      color: var(--cascivo-color-text);
    }
    &:focus-visible {
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .presets {
    display: flex;
    flex-wrap: wrap;
    gap: var(--cascivo-space-1);
    padding-block-end: var(--cascivo-space-2);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .preset {
    padding-block: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-3);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    background: none;
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    outline: none;

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
    }
    &:focus-visible {
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .footer {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--cascivo-space-2);
    padding-block-start: var(--cascivo-space-2);
    border-block-start: 1px solid var(--cascivo-color-border);
  }

  .clearBtn,
  .applyBtn {
    padding-block: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-4);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    outline: none;

    &:focus-visible {
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .clearBtn {
    color: var(--cascivo-color-text);
    background: none;
    border: 1px solid var(--cascivo-color-border);

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
    }
  }

  .applyBtn {
    color: var(--cascivo-color-primary-fg);
    background-color: var(--cascivo-color-primary);
    border: 1px solid transparent;

    &:hover {
      background-color: var(--cascivo-color-primary-hover);
    }
  }
}
